// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  const conditionLabel = useMemo(() => {
    const value = props.condition.trim().toLowerCase();
    if (value.includes('sun') || value.includes('clear')) return 'Sunny';
    if (value.includes('rain') || value.includes('drizzle') || value.includes('storm')) return 'Rainy';
    if (value.includes('cloud') || value.includes('overcast') || value.includes('fog')) return 'Cloudy';
    if (value.includes('snow') || value.includes('sleet')) return 'Snowy';
    return props.condition || 'Unknown';
  }, [props.condition]);

  const conditionIcon = useMemo(() => {
    const value = conditionLabel.toLowerCase();
    if (value.includes('sun')) return '☀️';
    if (value.includes('rain')) return '🌧️';
    if (value.includes('cloud')) return '☁️';
    if (value.includes('snow')) return '❄️';
    if (value.includes('storm')) return '⛈️';
    if (value.includes('fog')) return '🌫️';
    return '🌡️';
  }, [conditionLabel]);

  const forecastItems = useMemo(() => {
    return (props.forecast || []).slice(0, 5).map((item, index) => ({
      key: `${item.day ?? 'day'}-${index}`,
      day: item.day ?? `Day ${index + 1}`,
      icon: item.icon ?? conditionIcon,
      high: item.high,
      low: item.low,
    }));
  }, [conditionIcon, props.forecast]);

  return {
    conditionLabel,
    conditionIcon,
    forecastItems,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const temperatureText = `${props.temperature}°${props.unit}`;
  const humidityText = `${props.humidity}%`;
  const windText = `${props.windSpeed}`;

  return (
    <Container maxWidth="lg" padding={0}>
      <Card shadow="md" radius="xl" padding={0} border>
        <Box
          paddingX={24}
          paddingY={20}
          background="var(--ggui-color-container, #ede9fe)"
        >
          <Stack gap={12}>
            <Row align="center" justify="between">
              <Stack gap={4}>
                <Text variant="overline" color="var(--ggui-color-onContainer, #4c1d95)">
                  {props.city}
                </Text>
                <Heading level={2} color="var(--ggui-color-onContainer, #4c1d95)">
                  {state.conditionLabel}
                </Heading>
              </Stack>
              <Text
                variant="bodyLarge"
                weight="bold"
                color="var(--ggui-color-onContainer, #4c1d95)"
              >
                {state.conditionIcon}
              </Text>
            </Row>

            <Row align="center" justify="between" wrap>
              <Stack gap={2}>
                <Text
                  size="4xl"
                  weight="bold"
                  color="var(--ggui-color-onContainer, #4c1d95)"
                >
                  {temperatureText}
                </Text>
                <Text color="var(--ggui-color-onContainer, #4c1d95)">
                  {props.condition}
                </Text>
              </Stack>

              <Stack gap={8}>
                <Box
                  padding={12}
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                >
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                    <Text variant="bodyLarge" weight="bold">{humidityText}</Text>
                  </Stack>
                </Box>
                <Box
                  padding={12}
                  background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                >
                  <Stack gap={4}>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind</Text>
                    <Text variant="bodyLarge" weight="bold">{windText}</Text>
                  </Stack>
                </Box>
              </Stack>
            </Row>
          </Stack>
        </Box>

        <Box paddingX={24} paddingY={16}>
          <Stack gap={12}>
            <Heading level={4}>5-Day Forecast</Heading>
            <Row gap={12} wrap>
              {state.forecastItems.map((item) => (
                <Card key={item.key} padding={12} shadow="none" radius="md" border>
                  <Stack gap={8} align="center">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {item.day}
                    </Text>
                    <Text variant="bodyLarge" is="div">
                      {item.icon}
                    </Text>
                    <Text variant="label">
                      {typeof item.high === 'number' ? `${item.high}°${props.unit}` : `—°${props.unit}`}
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {typeof item.low === 'number' ? `${item.low}°${props.unit}` : `—°${props.unit}`}
                    </Text>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        </Box>
      </Card>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  const emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const trimmedName = name.trim();
  const trimmedEmail = email.trim();
  const trimmedComments = comments.trim();
  const satisfactionValue = satisfaction ? Number(satisfaction) : 0;
  const featureOptions = props.featureOptions;
  const satisfactionOptions = props.satisfactionLabels.slice(0, 5).map((label, index) => ({ value: String(index + 1), label }));
  const totalSteps = 5; // 4 survey steps + final review step
  const progressValue = ((currentStep - 1) / (totalSteps - 1)) * 100;

  const nameError = trimmedName ? '' : 'Name is required.';
  const emailError = trimmedEmail ? (emailPattern.test(trimmedEmail) ? '' : 'Please enter a valid email address.') : 'Email is required.';
  const commentsError = trimmedComments.length > 500 ? 'Comments must be 500 characters or fewer.' : '';
  const canGoNextStep1 = trimmedName !== '' && emailPattern.test(trimmedEmail);
  const canGoNextStep2 = satisfactionValue >= 1 && satisfactionValue <= 5;
  const canGoNextStep3 = features.length > 0;
  const canGoNextStep4 = trimmedComments.length <= 500;

  const reviewData = {
    name: trimmedName,
    email: trimmedEmail,
    satisfaction: satisfactionValue,
    features,
    comments: trimmedComments,
  };

  const toggleFeature = useCallback((feature: string) => {
    setFeatures((prev) => prev.includes(feature) ? prev.filter((item) => item !== feature) : [...prev, feature]);
  }, []);
  const goNext = useCallback(() => {
    setCurrentStep((prev) => Math.min(totalSteps, prev + 1));
  }, []);
  const goBack = useCallback(() => {
    setCurrentStep((prev) => Math.max(1, prev - 1));
  }, []);
  const handleSubmit = useCallback(() => {
    submit(reviewData);
    props.onSubmit(reviewData);
    setCurrentStep(1);
  }, [props, reviewData, submit]);

  return {
    submit,
    currentStep,
    setCurrentStep,
    name,
    setName,
    email,
    setEmail,
    satisfaction,
    setSatisfaction,
    features,
    setFeatures,
    comments,
    setComments,
    featureOptions,
    satisfactionOptions,
    nameError,
    emailError,
    commentsError,
    canGoNextStep1,
    canGoNextStep2,
    canGoNextStep3,
    canGoNextStep4,
    progressValue,
    totalSteps,
    toggleFeature,
    goNext,
    goBack,
    handleSubmit,
    reviewData,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        <Stack gap={12}>
          <Heading level={2}>Multi-step survey form</Heading>
          <Progress value={state.progressValue} max={100} showLabel />
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {Math.min(state.currentStep, 4)} of 4
          </Text>
        </Stack>

        <Card padding={24} radius="lg" shadow="sm">
          <Stack gap={20}>
            {state.currentStep === 1 ? (
              <Stack gap={16}>
                <Heading level={3}>About you</Heading>
                <Input
                  label="Name"
                  value={state.name}
                  onChange={state.setName}
                  required
                  error={state.nameError || undefined}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  value={state.email}
                  onChange={state.setEmail}
                  required
                  error={state.emailError || undefined}
                  placeholder="you@example.com"
                />
              </Stack>
            ) : null}

            {state.currentStep === 2 ? (
              <Stack gap={16}>
                <Heading level={3}>Satisfaction rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={state.satisfaction}
                  onChange={state.setSatisfaction}
                  options={state.satisfactionOptions}
                  error={state.canGoNextStep2 ? undefined : 'Please select a satisfaction rating.'}
                />
              </Stack>
            ) : null}

            {state.currentStep === 3 ? (
              <Stack gap={16}>
                <Heading level={3}>Feature interests</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Select all features you are interested in.
                </Text>
                <Stack gap={12}>
                  {state.featureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={state.features.includes(feature)}
                      onChange={() => state.toggleFeature(feature)}
                    />
                  ))}
                </Stack>
              </Stack>
            ) : null}

            {state.currentStep === 4 ? (
              <Stack gap={16}>
                <Heading level={3}>Comments</Heading>
                <TextArea
                  label="Open-ended comments"
                  value={state.comments}
                  onChange={state.setComments}
                  placeholder="Share any additional thoughts..."
                  maxLength={500}
                  showCount
                  helperText="Optional. Share anything that would improve your experience."
                  error={state.commentsError || undefined}
                />
              </Stack>
            ) : null}

            {state.currentStep === 5 ? (
              <Stack gap={16}>
                <Heading level={3}>Review your answers</Heading>
                <Stack gap={8}>
                  <Text variant="label">Name</Text>
                  <Text>{state.reviewData.name || '—'}</Text>
                  <Text variant="label">Email</Text>
                  <Text>{state.reviewData.email || '—'}</Text>
                  <Text variant="label">Satisfaction</Text>
                  <Text>{state.reviewData.satisfaction ? `${state.reviewData.satisfaction}. ${state.satisfactionOptions[state.reviewData.satisfaction - 1]?.label ?? ''}` : '—'}</Text>
                  <Text variant="label">Features</Text>
                  <Text>{state.reviewData.features.length ? state.reviewData.features.join(', ') : 'None selected'}</Text>
                  <Text variant="label">Comments</Text>
                  <Text>{state.reviewData.comments || '—'}</Text>
                </Stack>
              </Stack>
            ) : null}

            <Divider />

            <Row justify="between" align="center">
              <Button variant="ghost" onClick={state.goBack} disabled={state.currentStep === 1}>
                Back
              </Button>
              {state.currentStep < state.totalSteps ? (
                <Button
                  variant="primary"
                  onClick={() => {
                    if (state.currentStep === 1 && state.canGoNextStep1) {
                      state.goNext();
                      return;
                    }
                    if (state.currentStep === 2 && state.canGoNextStep2) {
                      state.goNext();
                      return;
                    }
                    if (state.currentStep === 3 && state.canGoNextStep3) {
                      state.goNext();
                      return;
                    }
                    if (state.currentStep === 4 && state.canGoNextStep4) {
                      state.goNext();
                    }
                  }}
                  disabled={
                    (state.currentStep === 1 && !state.canGoNextStep1) ||
                    (state.currentStep === 2 && !state.canGoNextStep2) ||
                    (state.currentStep === 3 && !state.canGoNextStep3) ||
                    (state.currentStep === 4 && !state.canGoNextStep4)
                  }
                >
                  Next
                </Button>
              ) : (
                <Button
                  variant="primary"
                  onClick={state.handleSubmit}
                  disabled={!state.canGoNextStep1 || !state.canGoNextStep2 || !state.canGoNextStep3 || !state.canGoNextStep4}
                >
                  Submit
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  const normalizeColumnId = useCallback((value?: string) => {
    const incoming = (value || '').toLowerCase();
    const found = props.columns.find((column) => {
      const id = (column.id || '').toLowerCase();
      const name = (column.name || '').toLowerCase();
      return incoming === id || incoming === name;
    });
    return found?.id || props.columns[0]?.id || 'todo';
  }, [props.columns]);

  const columnOptions = props.columns.map((column) => ({
    value: column.id || column.name || 'column',
    label: column.name || column.id || 'Column',
  }));

  const priorityOptions = [
    { value: 'low', label: 'Low' },
    { value: 'medium', label: 'Medium' },
    { value: 'high', label: 'High' },
  ];

  const makeTask = useCallback((task: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }, fallbackId: string) => ({
    id: task.id || fallbackId,
    title: task.title || 'Untitled task',
    priority: task.priority || 'medium',
    assignee: task.assignee || '',
    column: normalizeColumnId(task.column),
    dueDate: task.dueDate || '',
  }), [normalizeColumnId]);

  const [tasks, setTasks] = useState(() => props.tasks.map((task, index) => makeTask(task, `task-${index + 1}`)));
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [newTaskDueDate, setNewTaskDueDate] = useState('');
  const [newTaskAssignee, setNewTaskAssignee] = useState('');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [showAddForColumn, setShowAddForColumn] = useState<string | null>(null);
  const [liveMessage, setLiveMessage] = useState<string>('');

  React.useEffect(() => {
    setTasks(props.tasks.map((task, index) => makeTask(task, `task-${index + 1}`)));
  }, [makeTask, props.tasks]);

  const taskCount = tasks.length;
  const doneColumnId = normalizeColumnId(props.columns.find((column) => (column.name || '').toLowerCase() === 'done')?.id || 'done');
  const completedCount = tasks.filter((task) => normalizeColumnId(task.column) === doneColumnId).length;

  const groupedTasks = props.columns.reduce((acc, column) => {
    const id = normalizeColumnId(column.id || column.name || 'column');
    acc[id] = tasks.filter((task) => normalizeColumnId(task.column) === id);
    return acc;
  }, {} as Record<string, typeof tasks>);

  const taskUpdate = useCallback((payload: ActionTaskUpdatePayload) => {
    return payload;
  }, []);

  const taskChanged = { latest: null, all: [] } as { latest: StreamTaskChanged | null; all: StreamTaskChanged[] };

  const commitTaskUpdate = useCallback((action: string, taskId: string, data: { column: string }) => {
    taskUpdate({ action, taskId, data });
  }, [taskUpdate]);

  const moveTask = useCallback((taskId: string, columnId: string) => {
    const normalizedColumn = normalizeColumnId(columnId);
    setTasks((current) => current.map((task) => task.id === taskId ? { ...task, column: normalizedColumn } : task));
    commitTaskUpdate('move', taskId, { column: normalizedColumn });
  }, [commitTaskUpdate, normalizeColumnId]);

  const saveTaskTitle = useCallback((taskId: string, title: string) => {
    const trimmed = title.trim();
    if (!trimmed) return;
    setTasks((current) => current.map((task) => task.id === taskId ? { ...task, title: trimmed } : task));
    const column = tasks.find((task) => task.id === taskId)?.column || 'todo';
    commitTaskUpdate('edit', taskId, { column });
    setEditingTaskId(null);
  }, [commitTaskUpdate, tasks]);

  const createTask = useCallback((columnId: string) => {
    const id = `task-${Date.now()}-${Math.random().toString(16).slice(2)}`;
    const normalizedColumn = normalizeColumnId(columnId);
    const task = {
      id,
      title: newTaskTitle.trim() || 'New task',
      priority: newTaskPriority,
      assignee: newTaskAssignee.trim(),
      column: normalizedColumn,
      dueDate: newTaskDueDate,
    };
    setTasks((current) => [...current, task]);
    commitTaskUpdate('create', id, { column: normalizedColumn });
    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setNewTaskDueDate('');
    setNewTaskAssignee('');
    setShowAddForColumn(null);
  }, [commitTaskUpdate, newTaskAssignee, newTaskDueDate, newTaskPriority, newTaskTitle, normalizeColumnId]);

  React.useEffect(() => {
    if (!taskChanged.latest?.task) return;
    setTasks((current) => {
      const incoming = makeTask(taskChanged.latest!.task!, taskChanged.latest!.task?.id || `task-${Date.now()}`);
      if (taskChanged.latest?.action === 'delete') {
        return current.filter((task) => task.id !== incoming.id);
      }
      const exists = current.some((task) => task.id === incoming.id);
      if (exists) {
        return current.map((task) => task.id === incoming.id ? { ...task, ...incoming } : task);
      }
      return [...current, incoming];
    });
    setLiveMessage(`${taskChanged.latest.action || 'update'} event received for ${taskChanged.latest.task?.title || 'a task'}.`);
  }, [makeTask, taskChanged.latest]);

  return {
    taskUpdate,
    taskChanged,
    tasks,
    props,
    columnOptions,
    priorityOptions,
    taskCount,
    completedCount,
    groupedTasks,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    newTaskDueDate,
    setNewTaskDueDate,
    newTaskAssignee,
    setNewTaskAssignee,
    editingTaskId,
    setEditingTaskId,
    editingTitle,
    setEditingTitle,
    showAddForColumn,
    setShowAddForColumn,
    moveTask,
    saveTaskTitle,
    createTask,
    liveMessage,
  };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        <Card padding={20} shadow="sm">
          <Stack gap={12}>
            <Row align="center" justify="between" gap={16} wrap>
              <Stack gap={4}>
                <Heading level={2}>Kanban Board</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Track work across columns and collaborate in real time.
                </Text>
              </Stack>
              <Row align="center" gap={12} wrap>
                <Badge variant="primary">Total {state.taskCount}</Badge>
                <Badge variant="success">Done {state.completedCount}</Badge>
                <Badge variant="secondary">Open {Math.max(0, state.taskCount - state.completedCount)}</Badge>
              </Row>
            </Row>
            {state.liveMessage ? (
              <Alert variant="info" title="Live update">
                {state.liveMessage}
              </Alert>
            ) : null}
          </Stack>
        </Card>

        <Row gap={16} align="stretch" wrap>
          {state.props.columns.map((column) => {
            const columnId = state.columnOptions.find((option) => option.value === (column.id || column.name || 'column'))?.value || state.props.columns[0]?.id || 'todo';
            const columnTasks = state.groupedTasks[columnId] || [];
            return (
              <Card key={columnId} padding={16} shadow="sm" border radius="lg" as={Hoverable}>
                <Stack gap={12}>
                  <Row align="center" justify="between" gap={12}>
                    <Heading level={4}>{column.name || 'Column'}</Heading>
                    <Badge variant="secondary">{columnTasks.length}</Badge>
                  </Row>

                  <Stack gap={12}>
                    {columnTasks.length ? columnTasks.map((task) => {
                      const priorityVariant = task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'success';
                      const taskColumns = state.columnOptions.filter((option) => option.value !== task.column);
                      return (
                        <Card key={task.id} padding={12} shadow="none" border radius="md">
                          <Stack gap={8}>
                            <Row align="start" justify="between" gap={12}>
                              <Stack gap={4} style={{ flex: 1 }}>
                                {state.editingTaskId === task.id ? (
                                  <Stack gap={8}>
                                    <Input
                                      label="Task title"
                                      value={state.editingTitle}
                                      onChange={state.setEditingTitle}
                                      placeholder="Task title"
                                    />
                                    <Row justify="end" gap={8}>
