// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}

function useComponent(props: Props) {
  const [query, setQuery] = useState('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(
    props.elements[0]?.atomicNumber ?? null
  );

  const categoryColors = useMemo(() => ({
    'alkali-metal': 'var(--ggui-color-error-500, #dc2626)',
    'alkaline-earth-metal': 'var(--ggui-color-warning-500, #d97706)',
    'transition-metal': 'var(--ggui-color-primary-600, #0284c7)',
    'post-transition-metal': 'var(--ggui-color-info-500, #0284c7)',
    metalloid: 'var(--ggui-color-success-500, #16a34a)',
    nonmetal: 'var(--ggui-color-primary-400, #38bdf8)',
    halogen: 'var(--ggui-color-error-500, #dc2626)',
    'noble-gas': 'var(--ggui-color-info-500, #0284c7)',
    lanthanide: 'var(--ggui-color-warning-500, #d97706)',
    actinide: 'var(--ggui-color-error-600, #dc2626)',
    unknown: 'var(--ggui-color-outlineVariant, #e4e4e7)',
  }), []);

  const normalizedQuery = query.trim().toLowerCase();

  const filteredElements = useMemo(() => {
    if (!normalizedQuery) return props.elements;
    return props.elements.filter((element) => {
      const name = (element.name ?? '').toLowerCase();
      const symbol = (element.symbol ?? '').toLowerCase();
      return name.includes(normalizedQuery) || symbol.includes(normalizedQuery);
    });
  }, [normalizedQuery, props.elements]);

  const selectedElement = useMemo(() => {
    const current = props.elements.find(
      (element) => element.atomicNumber != null && element.atomicNumber === selectedAtomicNumber
    ) ?? null;

    if (current && filteredElements.some((element) => element.atomicNumber === current.atomicNumber)) {
      return current;
    }

    return filteredElements[0] ?? null;
  }, [filteredElements, props.elements, selectedAtomicNumber]);

  const handleSelectElement = useCallback((element: Props['elements'][number]) => {
    setSelectedAtomicNumber(element.atomicNumber ?? null);
  }, []);

  const handleQueryChange = useCallback((value: string) => {
    setQuery(value);
  }, []);

  const legendCategories = useMemo(() => {
    const seen = new Set<string>();
    const categories: string[] = [];
    props.elements.forEach((element) => {
      const category = (element.category ?? 'unknown').toLowerCase();
      if (!seen.has(category)) {
        seen.add(category);
        categories.push(category);
      }
    });
    return categories;
  }, [props.elements]);

  return {
    query,
    setQuery: handleQueryChange,
    selectedElement,
    setSelectedElement: handleSelectElement,
    filteredElements,
    legendCategories,
    categoryColors,
  };
}

