}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const addToCart = useCallback((payload: ActionAddToCartPayload) => {
    void payload;
  }, []);
  const product = props.product ?? {};
  const productId = product.id ?? '';
  const name = product.name ?? 'Product';
  const price = typeof product.price === 'number' ? product.price : 0;
  const currency = product.currency ?? 'USD';
  const rating = typeof product.rating === 'number' ? Math.max(0, Math.min(5, product.rating)) : 0;
  const reviewCount = typeof product.reviewCount === 'number' ? product.reviewCount : 0;
  const stock = typeof product.stock === 'number' ? Math.max(0, Math.floor(product.stock)) : 0;
  const description = product.description ?? '';
  const specifications = Array.isArray(product.specifications) ? product.specifications : [];
  const reviews = Array.isArray(product.reviews) ? product.reviews : [];

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const formatPrice = useCallback((value: number, curr: string) => {
    try {
      return new Intl.NumberFormat(undefined, { style: 'currency', currency: curr }).format(value);
    } catch {
      return `${curr} ${value.toFixed(2)}`;
    }
  }, []);

  const clampQuantity = useCallback((value: number) => {
    const next = Math.max(1, Math.min(stock || 1, Math.floor(value)));
    return Number.isFinite(next) ? next : 1;
  }, [stock]);

  const handleDecrement = useCallback(() => {
    setQuantity((current) => clampQuantity(current - 1));
  }, [clampQuantity]);

  const handleIncrement = useCallback(() => {
    setQuantity((current) => clampQuantity(current + 1));
  }, [clampQuantity]);

  const handleQuantityChange = useCallback((value: string) => {
    const parsed = Number(value);
    setQuantity(clampQuantity(Number.isNaN(parsed) ? 1 : parsed));
  }, [clampQuantity]);

  const handleAddToCart = useCallback(() => {
    if (!productId || stock <= 0) return;
    addToCart({ productId, quantity: clampQuantity(quantity) });
  }, [addToCart, clampQuantity, productId, quantity, stock]);

  const stockStatus = stock <= 0 ? 'Out of Stock' : stock <= 5 ? 'Low Stock' : 'In Stock';
  const stockVariant = stock <= 0 ? 'error' : stock <= 5 ? 'warning' : 'success';
  const canAddToCart = Boolean(productId) && stock > 0;

  return {
    addToCart,
    productId,
    name,
    price,
    currency,
    rating,
    reviewCount,
    stock,
    description,
    specifications,
    reviews,
    quantity,
    activeTab,
    setActiveTab,
    handleDecrement,
    handleIncrement,
    handleQuantityChange,
    handleAddToCart,
    formatPrice,
    stockStatus,
    stockVariant,
    canAddToCart,
  };
}

