    const optimisticSignature = buildSignature(optimisticMessage);
    messageSignatureRef.current.add(optimisticSignature);
    setMessages((prev) => [...prev, optimisticMessage]);
    sendMessage({ text, timestamp });
    setDraft('');
  }, [buildSignature, draft, props.currentUser, sendMessage]);

  const handleKeyDown = useCallback((event: React.KeyboardEvent<HTMLInputElement>) => {
    if (event.key === 'Enter') {
      event.preventDefault();
      handleSend();
    }
  }, [handleSend]);

  React.useEffect(() => {
    setMessages(props.messages || []);
    messageSignatureRef.current = new Set((props.messages || []).map((item) => buildSignature(item)));
    lastTypingSignatureRef.current = '';
    setTypingActive(false);
    setTypingSender('');
  }, [buildSignature, props.messages]);

  React.useEffect(() => {
    const handler = (event: Event) => {
      const customEvent = event as CustomEvent<{ type?: string; message?: StreamMessage; typing?: StreamTyping; sender?: string; active?: boolean; text?: string; timestamp?: string }>;
      const detail = customEvent.detail || {};
      const eventType = detail.type || (detail.message ? 'message' : detail.typing ? 'typing' : 'unknown');

      if (eventType === 'message' && detail.message) {
        const incoming = detail.message as StreamMessage;
        const signature = buildSignature(incoming);
        if (messageSignatureRef.current.has(signature)) return;
        messageSignatureRef.current.add(signature);
        setMessages((prev) => [...prev, incoming]);
        return;
      }

      if (eventType === 'typing') {
        const typing = detail.typing || { sender: detail.sender, active: detail.active };
        const typingSignature = `${typing.sender || ''}:${typing.active ? '1' : '0'}`;
        if (typingSignature === lastTypingSignatureRef.current) return;
        lastTypingSignatureRef.current = typingSignature;
        setTypingSender(typing.sender || '');
        setTypingActive(Boolean(typing.active));
      }
    };

    window.addEventListener('ggui:agent-data', handler);
    return () => window.removeEventListener('ggui:agent-data', handler);
  }, [buildSignature]);

  React.useEffect(() => {
    const latest = messages[messages.length - 1];
    if (!latest) return;
    messageSignatureRef.current.add(buildSignature(latest));
  }, [buildSignature, messages]);

  React.useEffect(() => {
    if (!listRef.current) return;
    listRef.current.scrollTo({ top: listRef.current.scrollHeight, behavior: 'smooth' });
  }, [messages.length, typingActive]);

  return {
    draft,
    setDraft,
    messages,
    typingActive,
    typingSender,
    listRef,
    handleSend,
    handleKeyDown,
    participantBadgeLabel,
    currentUserMessageCount,
  };
}
}


