import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };

function useComponent(props: Props) {
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState(new Date().toISOString());
  const [marketState, setMarketState] = useState<'open' | 'closed' | 'pre-market' | 'after-hours' | ''>('');
  const [flashSymbols, setFlashSymbols] = useState<string[]>([]);
  const flashTimersRef = useRef<Record<string, number>>({});

  const streamHookAny = React as typeof React & {
    useStream?: <T,>(name: string) => { latest: T | null; all: T[] };
  };
  const priceStream = streamHookAny.useStream ? streamHookAny.useStream<StreamPriceUpdate>('priceUpdate') : { latest: null, all: [] as StreamPriceUpdate[] };
  const marketStream = streamHookAny.useStream ? streamHookAny.useStream<StreamMarketStatus>('marketStatus') : { latest: null, all: [] as StreamMarketStatus[] };

  const formatTime = useCallback((value: string) => {
    const date = new Date(value);
    return Number.isNaN(date.getTime()) ? value : date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
  }, []);

  React.useEffect(() => {
    setStocks(props.stocks || []);
  }, [props.stocks]);

  React.useEffect(() => {
    const latest = priceStream.latest;
    if (!latest || !latest.symbol) return;

    setStocks((current) => {
      const nextStocks = current.map((stock) =>
        stock.symbol === latest.symbol
          ? {
              ...stock,
              price: typeof latest.price === 'number' ? latest.price : stock.price,
              change: typeof latest.change === 'number' ? latest.change : stock.change,
              changePercent: typeof latest.changePercent === 'number' ? latest.changePercent : stock.changePercent,
            }
          : stock
      );
      if (!current.some((stock) => stock.symbol === latest.symbol)) {
        nextStocks.unshift({ symbol: latest.symbol, price: latest.price, change: latest.change, changePercent: latest.changePercent });
      }
      return nextStocks;
    });
    setLastUpdated(new Date().toISOString());
    setFlashSymbols((current) => Array.from(new Set([...current, latest.symbol as string])));
    if (flashTimersRef.current[latest.symbol]) {
      window.clearTimeout(flashTimersRef.current[latest.symbol]);
    }
    flashTimersRef.current[latest.symbol] = window.setTimeout(() => {
      setFlashSymbols((current) => current.filter((symbol) => symbol !== latest.symbol));
      delete flashTimersRef.current[latest.symbol as string];
    }, 1200);
  }, [priceStream.latest]);

  React.useEffect(() => {
    const latest = marketStream.latest;
    if (!latest || !latest.status) return;
    setMarketState(latest.status);
    if (latest.timestamp) setLastUpdated(latest.timestamp);
  }, [marketStream.latest]);

  React.useEffect(() => {
    return () => {
      Object.values(flashTimersRef.current).forEach((timer) => window.clearTimeout(timer));
      flashTimersRef.current = {};
    };
  }, []);

  const sortedStocks = stocks;

  const getChangeTone = useCallback((change?: number) => (typeof change === 'number' && change < 0 ? 'error' : 'success'), []);

  const formatPrice = useCallback((price?: number) => {
    if (typeof price !== 'number' || Number.isNaN(price)) {
      return '--';
    }
    return price.toFixed(2);
  }, []);

  const formatChange = useCallback((value?: number) => {
    if (typeof value !== 'number' || Number.isNaN(value)) {
      return '--';
    }
    return `${value > 0 ? '+' : ''}${value.toFixed(2)}`;
  }, []);

  const formatPercent = useCallback((value?: number) => {
    if (typeof value !== 'number' || Number.isNaN(value)) {
      return '--';
    }
    return `${value > 0 ? '+' : ''}${value.toFixed(2)}%`;
  }, []);

  return { priceUpdate: priceStream.latest, marketStatus: marketStream.latest, stocks: sortedStocks, lastUpdated, marketState, flashSymbols, formatTime, getChangeTone, formatPrice, formatChange, formatPercent };
}
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4, 16px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Row align="center" justify="between">
          <Heading level={2}>Market Watch</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Last Updated: {state.formatTime(state.lastUpdated)}
          </Text>
        </Row>
        {state.marketState ? (
          <Badge variant={state.marketState === 'closed' ? 'error' : 'success'}>
            {state.marketState}
          </Badge>
        ) : null}
        <Card padding="var(--ggui-spacing-4, 16px)" radius="lg">
          <CardGrid columns={3} gap={16}>
            {state.stocks.map((stock) => {
              const tone = state.getChangeTone(stock.change);
              const isFlash = state.flashSymbols.includes(stock.symbol || '');
              const positive = typeof stock.change === 'number' ? stock.change >= 0 : true;
              const cardBorder = tone === 'success' ? 'var(--ggui-color-success-200, var(--ggui-color-outlineVariant, #e4e4e7))' : 'var(--ggui-color-error-200, var(--ggui-color-outlineVariant, #e4e4e7))';
              const textTone = tone === 'success' ? 'var(--ggui-color-success-700, var(--ggui-color-onSurface, #18181b))' : 'var(--ggui-color-error-700, var(--ggui-color-onSurface, #18181b))';
              const accentTone = tone === 'success' ? 'var(--ggui-color-success-600, var(--ggui-color-onSurfaceVariant, #52525b))' : 'var(--ggui-color-error-600, var(--ggui-color-onSurfaceVariant, #52525b))';
              return (
                <Card
                  key={stock.symbol || stock.name}
                  padding="var(--ggui-spacing-4, 16px)"
                  radius="lg"
                  border
                  shadow="sm"
                  as={Pressable}
                  pressStyle={{ opacity: 0.96 }}
                  style={{
                    borderColor: cardBorder,
                    animation: isFlash ? 'ggui-fadeIn 200ms ease-out, ggui-scaleIn 200ms ease-out' : undefined,
                  }}
                >
                  <Stack gap="var(--ggui-spacing-2, 8px)">
                    <Heading level={3} color={textTone}>
                      {stock.symbol || '--'}
                    </Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">{stock.name || '--'}</Text>
                    <Text variant="bodyLarge" weight="bold">${state.formatPrice(stock.price)}</Text>
                    <Text color={accentTone}>
                      {positive ? '▲' : '▼'} {state.formatChange(stock.change)} ({state.formatPercent(stock.changePercent)})
                    </Text>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        </Card>
      </Stack>
    </Container>
  );
}

