                placeholder="Select a role"
                required
              />
              <Toggle
                label="Email notifications"
                checked={state.emailNotifications}
                onChange={state.setEmailNotifications}
              />
              <Toggle
                label="Dark theme"
                checked={state.theme === 'dark'}
                onChange={(checked) => state.setTheme(checked ? 'dark' : 'light')}
              />
            </Stack>
          </Card>
        ) : (
          <Card padding={24} shadow="sm">
            <Stack gap={16}>
              <Heading level={3}>Review & Confirm</Heading>
              <Stack gap={8}>
                <Text variant="body">Name: {state.name || '—'}</Text>
                <Text variant="body">Email: {state.email || '—'}</Text>
                <Text variant="body">Avatar: {state.avatar || '—'}</Text>
                <Text variant="body">Role: {state.role || '—'}</Text>
                <Text variant="body">Email notifications: {state.emailNotifications ? 'On' : 'Off'}</Text>
                <Text variant="body">Theme: {state.theme}</Text>
              </Stack>
            </Stack>
          </Card>
        )}

        <Row justify="between" align="center">
          <Button variant="outline" onClick={state.handleBack} disabled={!state.canGoBack}>
            Go Back
          </Button>
          {state.step < 3 ? (
            <Button variant="primary" onClick={state.handleNext} disabled={!state.canGoNext}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={state.handleComplete} disabled={!state.canSubmit}>
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
